<?php include __DIR__.'/_init.php'; if($_SERVER['REQUEST_METHOD']==='POST'){if(!verify_csrf($_POST['csrf_token']??''))die('CSRF');$db->prepare('UPDATE payments SET status=? WHERE id=?')->execute([sanitize($_POST['status']),(int)$_POST['id']]);redirect('/admin/payments.php');}
$rows=$db->query('SELECT p.*,s.full_name,c.title FROM payments p JOIN students s ON s.id=p.student_id JOIN courses c ON c.id=p.course_id ORDER BY p.id DESC')->fetchAll();?><h2>Payments</h2><table border="1"><tr><th>Student</th><th>Course</th><th>Amount</th><th>Status</th><th>Razorpay</th><th>Update</th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['full_name'])?></td><td><?=e($r['title'])?></td><td><?=e($r['amount'])?></td><td><?=e($r['status'])?></td><td><?=e($r['razorpay_payment_id'])?></td><td><form method="post"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input type="hidden" name="id" value="<?=$r['id']?>"><select name="status"><option>created</option><option>paid</option><option>failed</option><option>refunded</option></select><button>Save</button></form></td></tr><?php endforeach;?></table>
